import heapq
class Solution:
    def minMoves(self, matrix):
        m = len(matrix)
        n = len(matrix[0])
        from collections import defaultdict
        groups = defaultdict(list)
        for i in range(m):
            for j in range(n):
                c = matrix[i][j]
                if 'A' <= c <= 'Z':
                    groups[c].append((i, j))
        INF = float('inf')
        dist = [[INF] * n for _ in range(m)]
        dist[0][0] = 0
        used = set()
        pq = [(0, 0, 0)]
        while pq:
            d, i, j = heapq.heappop(pq)
            if d > dist[i][j]:
                continue
            c = matrix[i][j]
            if 'A' <= c <= 'Z' and c not in used:
                used.add(c)
                for (ti, tj) in groups[c]:
                    if d < dist[ti][tj]:
                        dist[ti][tj] = d
                        heapq.heappush(pq, (d, ti, tj))
            for di, dj in ((1,0),(-1,0),(0,1),(0,-1)):
                ni, nj = i + di, j + dj
                if 0 <= ni < m and 0 <= nj < n and matrix[ni][nj] != '#':
                    if d + 1 < dist[ni][nj]:
                        dist[ni][nj] = d + 1
                        heapq.heappush(pq, (d + 1, ni, nj))
        return -1 if dist[m-1][n-1] == INF else dist[m-1][n-1]

