var minMoves = function(matrix) {
    const m = matrix.length, n = matrix[0].length;
    const groups = new Map();
    for (let i = 0; i < m; i++) for (let j = 0; j < n; j++) {
        const c = matrix[i][j];
        if (c >= 'A' && c <= 'Z') {
            if (!groups.has(c)) groups.set(c, []);
            groups.get(c).push([i, j]);
        }
    }
    const INF = Infinity;
    const dist = Array.from({length: m}, () => new Array(n).fill(INF));
    dist[0][0] = 0;
    const used = new Set();
    let dq = [[0, 0]];
    while (dq.length) {
        const [i, j] = dq.shift();
        const d = dist[i][j];
        const c = matrix[i][j];
        if (c >= 'A' && c <= 'Z' && !used.has(c)) {
            used.add(c);
            for (const [ti, tj] of groups.get(c)) {
                if (d < dist[ti][tj]) { dist[ti][tj] = d; dq.unshift([ti, tj]); }
            }
        }
        const dirs = [[1,0],[-1,0],[0,1],[0,-1]];
        for (const [di, dj] of dirs) {
            const ni = i + di, nj = j + dj;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n && matrix[ni][nj] !== '#') {
                if (d + 1 < dist[ni][nj]) { dist[ni][nj] = d + 1; dq.push([ni, nj]); }
            }
        }
    }
    return dist[m-1][n-1] === INF ? -1 : dist[m-1][n-1];
};
